import React, { useState, useEffect, useRef, useCallback } from 'react';
import { X, Plus, Maximize2, Minimize2, Settings } from 'lucide-react';

// Processador ANSI simples
function stripAnsi(text) {
  if (!text) return '';
  return text
    .replace(/\x1b\[[0-9;]*[a-zA-Z]/g, '')
    .replace(/\x1b\][^\x07]*\x07/g, '')
    .replace(/\x1b[()][AB012]/g, '')
    .replace(/\r\n/g, '\n')
    .replace(/\r/g, '\n');
}

export default function Terminal() {
  const [sessions, setSessions] = useState([]);
  const [activeSessionId, setActiveSessionId] = useState(null);
  const [devices, setDevices] = useState([]);
  const [showDeviceList, setShowDeviceList] = useState(false);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [showSettings, setShowSettings] = useState(false);

  const [settings, setSettings] = useState({
    fontSize: 14,
    bgColor: '#0a0a0a',
    textColor: '#00ff00',
    cursorColor: '#00ff00'
  });

  const terminalRef = useRef(null);
  const containerRef = useRef(null);

  useEffect(() => {
    const saved = localStorage.getItem('terminalSettings');
    if (saved) setSettings(JSON.parse(saved));
  }, []);

  useEffect(() => {
    localStorage.setItem('terminalSettings', JSON.stringify(settings));
  }, [settings]);

  useEffect(() => {
    fetch('/devices/api/list/')
      .then(res => res.json())
      .then(data => {
        const list = data.devices || data || [];
        setDevices(list.map(d => ({
          id: d.id,
          name: d.hostname || d.name,
          ip: d.ip_address || d.ip,
          vendor: d.vendor || 'linux',
          username: d.username || 'admin',
          port: d.port || 22
        })));
      })
      .catch(() => setDevices([]));
  }, []);

  useEffect(() => {
    if (terminalRef.current) {
      terminalRef.current.scrollTop = terminalRef.current.scrollHeight;
    }
  }, [sessions]);

  useEffect(() => {
    if (containerRef.current && activeSessionId) {
      containerRef.current.focus();
    }
  }, [activeSessionId]);

  const activeSession = sessions.find(s => s.id === activeSessionId);

  const connectToDevice = (device) => {
    const sessionId = 'session-' + Date.now();
    const protocol = window.location.protocol === 'https:' ? 'wss:' : 'ws:';
    const wsUrl = protocol + '//' + window.location.host + '/ws/ssh/';
    const ws = new WebSocket(wsUrl);

    const newSession = {
      id: sessionId,
      device: device,
      output: '',
      ws: ws,
      status: 'connecting'
    };

    ws.onopen = () => {
      ws.send(JSON.stringify({ type: 'connect', device_id: device.id }));
    };

    ws.onmessage = (event) => {
      try {
        const data = JSON.parse(event.data);
        const message = data.data || data.message || '';

        setSessions(prev => prev.map(s => {
          if (s.id === sessionId) {
            return { 
              ...s, 
              output: s.output + message,
              status: data.type === 'connected' ? 'connected' : s.status
            };
          }
          return s;
        }));
      } catch (e) {
        setSessions(prev => prev.map(s => {
          if (s.id === sessionId) {
            return { ...s, output: s.output + event.data };
          }
          return s;
        }));
      }
    };

    ws.onerror = () => {
      setSessions(prev => prev.map(s => {
        if (s.id === sessionId) {
          return { ...s, status: 'error', output: s.output + '\r\n[ERRO] Falha na conexao\r\n' };
        }
        return s;
      }));
    };

    ws.onclose = () => {
      setSessions(prev => prev.map(s => {
        if (s.id === sessionId) {
          return { ...s, status: 'disconnected', output: s.output + '\r\n[DESCONECTADO]\r\n' };
        }
        return s;
      }));
    };

    setSessions(prev => [...prev, newSession]);
    setActiveSessionId(sessionId);
    setShowDeviceList(false);
  };

  const sendChar = useCallback((char) => {
    if (activeSession && activeSession.ws && activeSession.ws.readyState === WebSocket.OPEN) {
      activeSession.ws.send(JSON.stringify({ data: char }));
    }
  }, [activeSession]);

  const handleKeyDown = useCallback((e) => {
    // Prevenir comportamento padrao
    if (e.key === 'Tab' || e.key === 'Backspace' || e.key.startsWith('Arrow')) {
      e.preventDefault();
      e.stopPropagation();
    }

    if (!activeSession || !activeSession.ws || activeSession.ws.readyState !== WebSocket.OPEN) {
      return false;
    }

    // Mapear teclas
    const keyMap = {
      'Tab': '\t',
      'Enter': '\r',
      'Backspace': '\x7f',
      'Delete': '\x1b[3~',
      'ArrowUp': '\x1b[A',
      'ArrowDown': '\x1b[B',
      'ArrowRight': '\x1b[C',
      'ArrowLeft': '\x1b[D',
      'Home': '\x1b[H',
      'End': '\x1b[F',
      'Escape': '\x1b'
    };

    // Ctrl combinations
    if (e.ctrlKey && e.key.length === 1) {
      const ctrlChar = String.fromCharCode(e.key.charCodeAt(0) - 96);
      sendChar(ctrlChar);
      return false;
    }

    // Teclas especiais
    if (keyMap[e.key]) {
      sendChar(keyMap[e.key]);
      return false;
    }

    // Caractere normal
    if (e.key.length === 1) {
      sendChar(e.key);
    }

    return false;
  }, [sendChar, activeSession]);

  const closeSession = (sessionId) => {
    const session = sessions.find(s => s.id === sessionId);
    if (session && session.ws) {
      session.ws.close();
    }
    setSessions(prev => prev.filter(s => s.id !== sessionId));
    if (activeSessionId === sessionId) {
      const remaining = sessions.filter(s => s.id !== sessionId);
      setActiveSessionId(remaining.length > 0 ? remaining[0].id : null);
    }
  };

  return (
    <div 
      className={'h-full flex flex-col' + (isFullscreen ? ' fixed inset-0 z-50' : '')}
      style={{ backgroundColor: settings.bgColor }}
    >
      {/* Header */}
      <div className="flex items-center justify-between bg-gray-800 border-b border-gray-700 px-4 py-2 flex-shrink-0">
        <div className="flex items-center gap-2">
          <h1 className="text-lg font-bold text-white">Terminal SSH</h1>
          <button onClick={() => setShowDeviceList(!showDeviceList)} className="flex items-center gap-1 px-2 py-1 bg-blue-600 text-white rounded text-sm hover:bg-blue-700">
            <Plus className="w-4 h-4" /> Nova
          </button>
        </div>
        <div className="flex items-center gap-2">
          <button onClick={() => setShowSettings(!showSettings)} className="p-1.5 rounded hover:bg-gray-700 text-gray-300">
            <Settings className="w-4 h-4" />
          </button>
          <button onClick={() => setIsFullscreen(!isFullscreen)} className="p-1.5 rounded hover:bg-gray-700 text-gray-300">
            {isFullscreen ? <Minimize2 className="w-4 h-4" /> : <Maximize2 className="w-4 h-4" />}
          </button>
        </div>
      </div>

      {/* Device List */}
      {showDeviceList && (
        <div className="absolute top-12 left-4 z-50 bg-gray-800 border border-gray-600 rounded-lg shadow-xl p-3 w-64">
          <h3 className="font-semibold mb-2 text-white text-sm">Dispositivos</h3>
          <div className="space-y-1 max-h-48 overflow-auto">
            {devices.length === 0 ? (
              <p className="text-gray-400 text-xs">Nenhum dispositivo</p>
            ) : (
              devices.map(device => (
                <button key={device.id} onClick={() => connectToDevice(device)} className="w-full flex items-center gap-2 p-2 rounded hover:bg-gray-700 text-left">
                  <div className={'w-2 h-2 rounded-full ' + (device.vendor === 'huawei' ? 'bg-red-500' : device.vendor === 'mikrotik' ? 'bg-green-500' : 'bg-blue-500')} />
                  <div>
                    <div className="text-white text-sm">{device.name}</div>
                    <div className="text-gray-400 text-xs">{device.ip}:{device.port}</div>
                  </div>
                </button>
              ))
            )}
          </div>
        </div>
      )}

      {/* Settings */}
      {showSettings && (
        <div className="absolute top-12 right-4 z-50 bg-gray-800 border border-gray-600 rounded-lg shadow-xl p-4 w-56">
          <h3 className="font-semibold mb-3 text-white text-sm">Configuracoes</h3>
          <div className="space-y-3">
            <div>
              <label className="text-gray-300 text-xs">Fonte: {settings.fontSize}px</label>
              <input type="range" min="10" max="24" value={settings.fontSize} onChange={(e) => setSettings({...settings, fontSize: parseInt(e.target.value)})} className="w-full" />
            </div>
            <div className="flex gap-2">
              <div>
                <label className="text-gray-300 text-xs block mb-1">Fundo</label>
                <input type="color" value={settings.bgColor} onChange={(e) => setSettings({...settings, bgColor: e.target.value})} className="w-10 h-8 rounded cursor-pointer" />
              </div>
              <div>
                <label className="text-gray-300 text-xs block mb-1">Texto</label>
                <input type="color" value={settings.textColor} onChange={(e) => setSettings({...settings, textColor: e.target.value})} className="w-10 h-8 rounded cursor-pointer" />
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Tabs */}
      {sessions.length > 0 && (
        <div className="flex bg-gray-900 border-b border-gray-700 overflow-x-auto flex-shrink-0">
          {sessions.map(session => (
            <div key={session.id} onClick={() => setActiveSessionId(session.id)} className={'flex items-center gap-2 px-3 py-1.5 border-r border-gray-700 cursor-pointer text-sm ' + (activeSessionId === session.id ? 'bg-gray-800' : 'hover:bg-gray-800')}>
              <div className={'w-2 h-2 rounded-full ' + (session.status === 'connected' ? 'bg-green-500' : session.status === 'connecting' ? 'bg-yellow-500 animate-pulse' : 'bg-red-500')} />
              <span className="text-gray-200">{session.device.name}</span>
              <button onClick={(e) => { e.stopPropagation(); closeSession(session.id); }} className="p-0.5 rounded hover:bg-red-500/30 text-gray-400"><X className="w-3 h-3" /></button>
            </div>
          ))}
        </div>
      )}

      {/* Terminal */}
      <div
        ref={containerRef}
        className="flex-1 overflow-auto outline-none"
        style={{ backgroundColor: settings.bgColor, padding: '8px' }}
        tabIndex={0}
        onKeyDown={handleKeyDown}
      >
        {sessions.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-full text-gray-500">
            <p>Clique em "Nova" para conectar</p>
          </div>
        ) : activeSession ? (
          <pre 
            ref={terminalRef}
            className="whitespace-pre-wrap font-mono"
            style={{ color: settings.textColor, fontSize: settings.fontSize + 'px', margin: 0 }}
          >
            {activeSession.output}
            <span className="inline-block w-2 animate-pulse" style={{ backgroundColor: settings.cursorColor, height: settings.fontSize + 'px', verticalAlign: 'text-bottom' }} />
          </pre>
        ) : null}
      </div>

      {/* Status */}
      {activeSession && (
        <div className="flex items-center justify-between px-4 py-1 text-xs bg-gray-900 border-t border-gray-700 text-gray-400 flex-shrink-0">
          <div className="flex items-center gap-2">
            <div className={'w-2 h-2 rounded-full ' + (activeSession.status === 'connected' ? 'bg-green-500' : 'bg-yellow-500')} />
            <span>{activeSession.device.name} - {activeSession.status === 'connected' ? 'Online' : 'Conectando...'}</span>
          </div>
          <span>TAB: autocomplete | Ctrl+C: cancelar</span>
        </div>
      )}
    </div>
  );
}
